import 'dart:convert';
import 'package:flutter/material.dart';
import 'package:task_manager_flutter/data/models/venda_model.dart';
import 'package:task_manager_flutter/data/models/negotiation_model.dart';
import 'package:task_manager_flutter/data/utils/api_links.dart';
import 'package:task_manager_flutter/data/models/network_response.dart';
import 'package:task_manager_flutter/data/services/network_caller.dart';
import 'package:task_manager_flutter/data/models/auth_utility.dart';

// Certifique-se de que esta classe inclui o parâmetro `onLoginSuccess`.
class LoginPopup extends StatelessWidget {
  final VoidCallback? onLoginSuccess;

  const LoginPopup({Key? key, this.onLoginSuccess}) : super(key: key);

  @override
  Widget build(BuildContext context) {
    return AlertDialog(
      title: const Text('Login'),
      content: const Text('Por favor, faça login para continuar.'),
      actions: [
        TextButton(
          onPressed: () {
            Navigator.of(context).pop();
          },
          child: const Text('Cancelar'),
        ),
        ElevatedButton(
          onPressed: () {
            // Simulação de login bem-sucedido
            if (onLoginSuccess != null) {
              onLoginSuccess!();
            }
            Navigator.of(context).pop();
          },
          child: const Text('Login'),
        ),
      ],
    );
  }
}
